function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    let maxProfit = 0;
    let totalProfit = 0;

    // Calculate the original profit
    for (let i = 0; i < n; i++) {
        totalProfit += strategy[i] * prices[i];
    }
    maxProfit = totalProfit;

    // Try to find the best modification
    for (let i = 0; i <= n - k; i++) {
        // Calculate the original sum for the k consecutive elements
        let originalSum = 0;
        for (let j = 0; j < k; j++) {
            originalSum += strategy[i + j] * prices[i + j];
        }

        // Calculate the modified sum for the k consecutive elements
        let modifiedSum = 0;
        for (let j = 0; j < k; j++) {
            if (j < k / 2) {
                modifiedSum += 0 * prices[i + j];
            } else {
                modifiedSum += 1 * prices[i + j];
            }
        }

        // Calculate the new profit with this modification
        const newProfit = totalProfit - originalSum + modifiedSum;
        if (newProfit > maxProfit) {
            maxProfit = newProfit;
        }
    }

    return maxProfit;
}
